// Consolidar dados para o Claude
const metricas = $('Buscar Métricas').first().json;
const projetos = $('Buscar Projetos Ativos').first().json;
const alertas = $('Buscar Alertas').first().json;

// Resumo dos projetos para contexto
const resumoProjetos = (Array.isArray(projetos) ? projetos : []).map(p => ({
  numero: p.numeroProjeto,
  cliente: p.clienteNome,
  tipo: p.tipoProjeto === 'AUDITORIA_CREDITOS' ? 'Auditoria' : 'Gestão de Passivo',
  etapa: p.etapaAtual,
  progresso: p.progressoPercent || 0,
  procuracaoVence: p.procuracao?.dataValidade || null,
  valorCreditos: p.resultadosAuditoria?.totalCreditosIdentificados || 0
}));

return [{
  json: {
    contexto: {
      metricas,
      resumoProjetos: JSON.stringify(resumoProjetos, null, 2),
      alertasCriticos: (Array.isArray(alertas) ? alertas : []).filter(a => a.severity === 'CRITICAL'),
      dataHoje: new Date().toLocaleDateString('pt-BR'),
      diaSemana: ['domingo','segunda','terça','quarta','quinta','sexta','sábado'][new Date().getDay()]
    }
  }
}];

