// Extrair texto da resposta do Claude
const response = $input.first().json;
const briefingText = response.content?.[0]?.text || 'Briefing não gerado.';

// Quebrar em chunks se > 4096 chars (limite WhatsApp)
const chunks = [];
if (briefingText.length <= 4096) {
  chunks.push(briefingText);
} else {
  const parts = briefingText.split('\n\n');
  let current = '';
  for (const part of parts) {
    if ((current + '\n\n' + part).length > 4000) {
      chunks.push(current.trim());
      current = part;
    } else {
      current += '\n\n' + part;
    }
  }
  if (current.trim()) chunks.push(current.trim());
}

return chunks.map((text, i) => ({ json: { text, part: i + 1, total: chunks.length } }));
